import{_ as e,o,c as r,ag as t}from"./chunks/framework.Bgwu_dgr.js";const u=JSON.parse('{"title":"주요 인물","description":"","frontmatter":{},"headers":[],"relativePath":"overview/people.md","filePath":"overview/people.md","lastUpdated":null}'),n={name:"overview/people.md"};function h(l,a,i,d,s,c){return o(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="주요-인물" tabindex="-1">주요 인물 <a class="header-anchor" href="#주요-인물" aria-label="Permalink to &quot;주요 인물&quot;">​</a></h1><p>이 발표에 등장하거나 언급되는 인물들을 정리한다.</p><hr><h2 id="발표자" tabindex="-1">발표자 <a class="header-anchor" href="#발표자" aria-label="Permalink to &quot;발표자&quot;">​</a></h2><h3 id="barry-zhang-anthropic-엔지니어" tabindex="-1">Barry Zhang -- Anthropic 엔지니어 <a class="header-anchor" href="#barry-zhang-anthropic-엔지니어" aria-label="Permalink to &quot;Barry Zhang -- Anthropic 엔지니어&quot;">​</a></h3><p>Anthropic에서 Agent Skills 프로젝트의 핵심 구축자 중 한 명이다. 발표에서 그는 &quot;세무 코드 처리라면 Mahesh보다 Barry가 낫다&quot;는 농담의 주인공이자, <strong>전문성이 범용 지능보다 실무에서 강하다</strong>는 논지를 상징하는 인물로 등장한다.</p><p>Zhang은 AI Engineer 컨퍼런스를 비롯한 공개 행사에서 에이전트 설계와 Claude Code의 엔지니어링 의사결정을 자주 공유해왔다. 실제로 Claude Code, Claude Agent SDK, 그리고 Skills 시스템의 설계 논의에 깊숙이 참여한 것으로 알려져 있다.</p><h3 id="mahesh-murag-anthropic-엔지니어" tabindex="-1">Mahesh Murag -- Anthropic 엔지니어 <a class="header-anchor" href="#mahesh-murag-anthropic-엔지니어" aria-label="Permalink to &quot;Mahesh Murag -- Anthropic 엔지니어&quot;">​</a></h3><p>Anthropic의 엔지니어로, Skills 생태계와 내부 시스템 구축에 관여했다. 발표에서는 Zhang이 농담 삼아 &quot;300 IQ 수학 천재&quot;라고 소개하는 역할을 맡으며, <strong>순수 지능만으로는 실무를 해결하지 못한다</strong>는 비유의 반대편에 선다.</p><p>Murag은 Model Context Protocol(MCP) 관련 커뮤니티에서도 활동해왔으며, MCP와 Skills의 역할 분담(연결 vs 전문성)을 명확히 설명하는 장면은 발표의 기술적 하이라이트 중 하나다.</p><hr><h2 id="발표에서-언급된-조직-및-프로젝트" tabindex="-1">발표에서 언급된 조직 및 프로젝트 <a class="header-anchor" href="#발표에서-언급된-조직-및-프로젝트" aria-label="Permalink to &quot;발표에서 언급된 조직 및 프로젝트&quot;">​</a></h2><h3 id="anthropic" tabindex="-1">Anthropic <a class="header-anchor" href="#anthropic" aria-label="Permalink to &quot;Anthropic&quot;">​</a></h3><p>Claude 모델 시리즈와 Claude Code를 만든 AI 안전 연구 기업. 이 발표의 맥락에서는 2025년 10월 Agent Skills를 공식 출시하고, 5주 만에 수천 개의 스킬이 생성되는 생태계를 형성한 주체다.</p><h3 id="claude-code" tabindex="-1">Claude Code <a class="header-anchor" href="#claude-code" aria-label="Permalink to &quot;Claude Code&quot;">​</a></h3><p>Anthropic의 첫 번째 코딩 에이전트이자, 발표자들이 **&quot;코드는 디지털 세계의 범용 인터페이스&quot;**라는 확신을 얻은 실험대. 발표는 Claude Code를 만들면서 관찰한 경험이 Skills의 설계로 이어졌음을 반복적으로 강조한다.</p><h3 id="cadence" tabindex="-1">Cadence <a class="header-anchor" href="#cadence" aria-label="Permalink to &quot;Cadence&quot;">​</a></h3><p>생명과학/바이오인포매틱스 영역의 스킬을 구축한 파트너사. EHR 데이터 분석과 과학 연구를 위한 기초 스킬의 사례로 언급된다.</p><h3 id="browserbase-stagehand" tabindex="-1">Browserbase (Stagehand) <a class="header-anchor" href="#browserbase-stagehand" aria-label="Permalink to &quot;Browserbase (Stagehand)&quot;">​</a></h3><p>웹 탐색/자동화 분야의 서드파티 스킬 제공자. Browserbase가 만든 Stagehand 스킬은 에이전트가 브라우저를 다루는 작업을 표준화된 방식으로 수행하게 해준다.</p><h3 id="notion" tabindex="-1">Notion <a class="header-anchor" href="#notion" aria-label="Permalink to &quot;Notion&quot;">​</a></h3><p>워크스페이스 이해와 연구를 위한 Notion 스킬을 출시한 파트너. 기업 내부 문서 검색, 작성, 분석 워크플로를 스킬로 패키지화한 사례다.</p><h3 id="model-context-protocol-mcp" tabindex="-1">Model Context Protocol (MCP) <a class="header-anchor" href="#model-context-protocol-mcp" aria-label="Permalink to &quot;Model Context Protocol (MCP)&quot;">​</a></h3><p>Anthropic이 개방형 표준으로 공개한 프로토콜. 발표에서 <strong>MCP = 외부 세계와의 연결, Skills = 전문성의 담지체</strong>라는 구도로 설명된다. 둘은 대체 관계가 아니라 서로를 보완한다.</p><h3 id="fortune-100-기업들-익명" tabindex="-1">Fortune 100 기업들 (익명) <a class="header-anchor" href="#fortune-100-기업들-익명" aria-label="Permalink to &quot;Fortune 100 기업들 (익명)&quot;">​</a></h3><p>발표에서는 이름을 특정하지 않으나, 대형 기업의 개발자 생산성 팀이 사내 코드 스타일과 빌드/배포 관행을 스킬로 인코딩하고 수천 명의 엔지니어에게 제공하는 사례가 언급된다. 또한 법무, 재무, 회계 부서의 <strong>비개발자 직군</strong>이 자신의 절차적 지식을 스킬로 만들고 있다는 관찰도 함께 제시된다.</p>',26)])])}const b=e(n,[["render",h]]);export{u as __pageData,b as default};
